import java.util.*;

public class LinkedListExample {
    public static void main(String[] args) {
        // Creating LinkedList
        System.out.println("=== Creating ===");
        LinkedList<String> list = new LinkedList<>();

        // Adding elements
        System.out.println("=== Adding ===");
        list.add("A");
        list.add("B");
        list.add("C");
        System.out.println("After add: " + list);

        // Adding at beginning/end (LinkedList-specific)
        list.addFirst("First");
        list.addLast("Last");
        System.out.println("After addFirst/addLast: " + list);

        // Adding at specific position
        list.add(2, "Middle");
        System.out.println("After insert: " + list);

        // Getting elements
        System.out.println("=== Getting ===");
        System.out.println("First: " + list.getFirst());
        System.out.println("Last: " + list.getLast());
        System.out.println("Index 2: " + list.get(2));

        // Peeking (without removing)
        System.out.println("=== Peeking ===");
        System.out.println("Peek First: " + list.peek());
        System.out.println("Peek First (same): " + list.peekFirst());
        System.out.println("Peek Last: " + list.peekLast());

        // Removing
        System.out.println("=== Removing ===");
        System.out.println("Remove First: " + list.removeFirst());
        System.out.println("Remove Last: " + list.removeLast());
        System.out.println("After removing first/last: " + list);

        // Polling (remove and return)
        System.out.println("=== Polling ===");
        System.out.println("Poll: " + list.poll());  // Remove first
        System.out.println("Poll First: " + list.pollFirst());
        System.out.println("Poll Last: " + list.pollLast());
        System.out.println("After polling: " + list);

        // Queue operations (FIFO)
        System.out.println("=== Queue operations ===");
        LinkedList<Integer> queue = new LinkedList<>();
        queue.offer(10);   // Add to end
        queue.offer(20);
        queue.offer(30);
        System.out.println("Queue: " + queue);
        System.out.println("Poll: " + queue.poll());  // Remove first (10)
        System.out.println("After poll: " + queue);
        System.out.println("Peek: " + queue.peek());  // Look at first (20)

        // Stack operations (LIFO)
        System.out.println("=== Stack operations ===");
        LinkedList<String> stack = new LinkedList<>();
        stack.push("A");   // Add to front
        stack.push("B");
        stack.push("C");
        System.out.println("Stack: " + stack);  // [C, B, A]
        System.out.println("Pop: " + stack.pop());  // Remove first (C)
        System.out.println("After pop: " + stack);  // [B, A]

        // LinkedList as List
        System.out.println("=== As List ===");
        System.out.println("Size: " + list.size());
        System.out.println("Is empty? " + list.isEmpty());

        // Iterating
        System.out.println("=== Iteration ===");
        for (String s : list) {
            System.out.println("  " + s);
        }
    }
}

phase2.brokenCode:
import java.util.*;

public class Test {
    public static void main(String[] args) {
        LinkedList<Integer> list = new LinkedList<>();

        // Accessing from empty list
        System.out.println(list.getFirst());  // ERROR!
    }
}

phase2.explanation:
getFirst() throws NoSuchElementException if the list is empty!

Unlike peekFirst() which returns null, getFirst() throws an exception.

FIX: Use peekFirst() which returns null on empty:
Integer first = list.peekFirst();
if (first != null) {
    System.out.println(first);
} else {
    System.out.println("List is empty!");
}

Or check if empty:
if (!list.isEmpty()) {
    System.out.println(list.getFirst());
}

Always prefer peek/poll over get/remove when you're not sure if the list is empty!

